&lt;li style=&quot;font-family: arial, helvetica, sans-serif; font-size: 10pt;&quot;&gt;&lt;span style=&quot;font-family: arial, helvetica, sans-serif; font-size: 10pt;&quot;&gt;Collaborate with internal cross-functional teams to build out fixed asset tagging process across 3 sites&lt;/span&gt;&lt;/li&gt;
&lt;li style=&quot;font-family: arial, helvetica, sans-serif; font-size: 10pt;&quot;&gt;&lt;span style=&quot;font-family: arial, helvetica, sans-serif; font-size: 10pt;&quot;&gt;Review monthly/quarterly/annual fixed asset roll forwards&amp;nbsp;&lt;/span&gt;&lt;/li&gt;
